1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEAR_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	
12	const INSURANCE_VALUE: Record<string, number> = {
13	  sword: 1000,
14	  amulet: 600,
15	  staff: 800,
16	  potion: 400,
17	  rune: 250,
18	  moonstone: 250,
19	};
20	
21	const COMPONENT_BASE_PREMIUM = 25;
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PREMIUM = 60;
25	
26	const NON_COMPONENT_BASE_PREMIUM: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);
34	
35	const basePremiumFor = (type: string): number =>
36	  isComponent(type) ? COMPONENT_BASE_PREMIUM : NON_COMPONENT_BASE_PREMIUM[type];
37	
38	type Item = {
39	  type: string;
40	  cursed?: boolean;
41	  enchantment?: number;
42	  material?: string;
43	};
44	type QuoteStep = { op: "quote"; items: Item[] };
45	type Damage = { itemType: string; amount: number };
46	type Incident = { cause: string; damages: Damage[] };
47	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
48	type Step = QuoteStep | ClaimStep;
49	type Customer = { yearsWithMHPCO: number };
50	type Scenario = { customer: Customer; steps: Step[] };
51	
52	type Policy = { items: Item[]; remainingCap: number };
53	
54	const groupedBasePremium = (type: string, count: number): number => {
55	  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
56	    return COMPONENT_BLOCK_PREMIUM;
57	  }
58	  return count * basePremiumFor(type);
59	};
60	
61	const countByType = (items: Item[]): Map<string, number> => {
62	  const counts = new Map<string, number>();
63	  for (const item of items) {
64	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
65	  }
66	  return counts;
67	};
68	
69	const sumBasePremiums = (items: Item[]): number =>
70	  Array.from(countByType(items)).reduce(
71	    (total, [type, count]) => total + groupedBasePremium(type, count),
72	    0,
73	  );
74	
75	const surchargeFor = (item: Item, applies: boolean, rate: number): number =>
76	  applies ? basePremiumFor(item.type) * rate : 0;
77	
78	const isCursed = (item: Item): boolean => item.cursed === true;
79	
80	const isHighlyEnchanted = (item: Item): boolean =>
81	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
82	
83	const itemSurchargeFor = (item: Item): number =>
84	  surchargeFor(item, isCursed(item), CURSE_SURCHARGE_RATE) +
85	  surchargeFor(item, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
86	
87	const sumItemSurcharges = (items: Item[]): number =>
88	  items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
89	
90	const firstInsuranceSurcharge = (basePremium: number): number =>
91	  basePremium * FIRST_INSURANCE_RATE;
92	
93	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
94	  customer.yearsWithMHPCO >= LOYALTY_YEAR_THRESHOLD
95	    ? basePremium * LOYALTY_DISCOUNT_RATE
96	    : 0;
97	
98	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
99	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
100	
101	const quotePremium = (
102	  items: Item[],
103	  customer: Customer,
104	  isFollowUp: boolean,
105	): number => {
106	  const basePremium = sumBasePremiums(items);
107	  const insurancePremium = Math.ceil(
108	    basePremium +
109	      sumItemSurcharges(items) +
110	      firstInsuranceSurcharge(basePremium) -
111	      loyaltyDiscount(basePremium, customer) -
112	      followUpDiscount(basePremium, isFollowUp),
113	  );
114	  return insurancePremium + PROCESSING_FEE;
115	};
116	
117	const insuranceSum = (items: Item[]): number =>
118	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
119	
120	const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;
121	
122	const runQuote = (
123	  step: QuoteStep,
124	  customer: Customer,
125	  isFollowUp: boolean,
126	): { result: { premium: number }; policy: Policy } => {
127	  const premium = quotePremium(step.items, customer, isFollowUp);
128	  const policy: Policy = {
129	    items: step.items,
130	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
131	  };
132	  return { result: { premium }, policy };
133	};
134	
135	const runClaim = (
136	  step: ClaimStep,
137	  policies: Policy[],
138	): { result: { payout: number; remainingCap: number }; policy: Policy } => {
139	  const policy = policies[step.policy];
140	  const payout = step.incident.damages.reduce(
141	    (sum, damage) => sum + damagePayout(damage),
142	    0,
143	  );
144	  const updatedPolicy: Policy = {
145	    ...policy,
146	    remainingCap: policy.remainingCap - payout,
147	  };
148	  return {
149	    result: { payout, remainingCap: updatedPolicy.remainingCap },
150	    policy: updatedPolicy,
151	  };
152	};
153	
154	const FIRST_STEP_INDEX = 0;
155	
156	export const runScenario = (scenario: Scenario): unknown => {
157	  const policies: Policy[] = [];
158	  const results = scenario.steps.map((step, index) => {
159	    if (step.op === "quote") {
160	      const isFollowUp = index > FIRST_STEP_INDEX;
161	      const { result, policy } = runQuote(step, scenario.customer, isFollowUp);
162	      policies.push(policy);
163	      return result;
164	    }
165	    const { result, policy } = runClaim(step, policies);
166	    policies[step.policy] = policy;
167	    return result;
168	  });
169	  return { results };
170	};
